# -*- coding: utf-8 -*-import timefrom pymycobot.mycobot import MyCobotfrom GrabParams_2 import grabParams# 初始化机械臂mc = MyCobot(grabParams.usb_dev, grabParams.baudrate)print("机械臂连接成功，准备单次测试...")# 待测试的角度（可直接修改这里的角度值）ZB = [-76.37, -18.28, 3.07, 24.96, -16.34, -49.65]  #准备ZQ = [-81.56, -44.56, 17.57, 23.9, -7.91, -46.75]   # 抓取位置TQ = [-88.94, 43.15, -99.93, 46.4, -2.54, -46.93]  # 抬起位置FZ = [-84.19, 0.0, -106.78, 99.93, -7.82, -46.49]  # 放置位置HZ = [-84.46, 63.28, -125.06, 60.11, -10.89, -47.98] #撤回# ZB  = [-80.59, -10.63, -13.44, 33.92, -8.96, -48.86] #yubei# YZQ =[-81.21, -55.63, 95.44, -27.5, -8.87, -45.7]#yuzhuaqu# ZQ  =[-79.62, -55.54, 23.73, 39.63, -11.07, -47.28]#zhuaqu# TQ  =[-86.13, 63.19, -146.6, 96.59, -9.49, -45.52]#anquan# FZ  =[-83.23, -30.93, -83.23, 118.91, -10.28, -46.31]#fangzhi# HZ  =[-88.59, 63.45, -145.72, 117.15, -7.11, -48.33]#anquan2SPEED = 65  # 移动速度# 测试流程try:    #0 准备工作    print("移动到摄像位置")    mc.send_angles(ZB, SPEED)    time.sleep(0.5)    # 1. 初始准备：打开夹爪    mc.set_gripper_value(255, 30)    time.sleep(0.5)    print("夹爪已打开")    # print("移动...")    # mc.send_angles(YZQ, SPEED)    # time.sleep(0.8)    # 2. 移动到抓取位置    print("移动到抓取位置...")    mc.send_angles(ZQ, SPEED)    time.sleep(0.8)    # 3. 闭合夹爪（模拟抓取）    print("执行抓取...")    mc.set_gripper_value(35, 50)    time.sleep(1.5)    # 4. 抬起    print("抬起物体...")    mc.send_angles(TQ, SPEED)    time.sleep(1)    # 5. 移动到放置位置    print("移动到放置位置...")    mc.send_angles(FZ, SPEED)    time.sleep(1)    # 6. 打开夹爪（模拟放置）    print("执行放置...")    mc.set_gripper_value(255, 65)    time.sleep(1.5)    #7.回撤放回    print("移动到安全区域...")    mc.send_angles(HZ, SPEED)    time.sleep(0.5)    #8.回到最初    print("移动到摄像位置")    mc.send_angles(ZB, SPEED)    time.sleep(0.5)    print("单次测试完成！")except Exception as e:    print("测试出错: {}".format(e))# 最终回到初始位置# mc.send_angles([11, -23, -39, -29, -3, 58], 50)time.sleep(3)## # -*- coding: utf-8 -*-## import time## from pymycobot.mycobot import MyCobot## from GrabParams_2 import grabParams#### # 初始化机械臂## mc = MyCobot(grabParams.usb_dev, grabParams.baudrate)## print("机械臂连接成功，准备单次测试...")#### # 待测试的角度（可直接修改这里的角度值）## ZB = [-76.37, -18.28, 3.07, 24.96, -16.34, -49.65]  #准备## ZQ = [-81.56, -44.56, 17.57, 23.9, -7.91, -46.75]   # 抓取位置## TQ =[-84.81, 52.99, -100.45, 44.12, -5.53, -46.31]# 抬起位置# 		# [-88.94, 43.15, -99.93, 46.4, -2.54, -46.93]      		[-81.73, 35.5, -106.87, 88.85, -11.33, -46.75] 		[-81.65, 50.36, -88.59, 49.83, -11.16, -46.49]# FZ =[-82.26, -29.88, -84.9, 112.67, -4.92, -47.81]  # 放置位置# 		#[-84.19, 0.0, -106.78, 99.93, -7.82, -46.49]# HZ =[-83.75, 33.04, -116.54, 78.83, -6.67, -46.4]  #撤回# 		#[-84.46, 63.28, -125.06, 60.11, -10.89, -47.98]# SPEED = 65  # 移动速度#### # 测试流程## try:##     #0 准备工作##     print("移动到摄像位置")##     mc.send_angles(ZB, SPEED)##     time.sleep(0.5)####     # 1. 初始准备：打开夹爪##     mc.set_gripper_value(255, 30)##     time.sleep(0.5)##     print("夹爪已打开")####     # 2. 移动到抓取位置##     print("移动到抓取位置...")##     mc.send_angles(ZQ, SPEED)##     time.sleep(0.8)####     # 3. 闭合夹爪（模拟抓取）##     print("执行抓取...")##     mc.set_gripper_value(35, 50)##     time.sleep(1.5)####     # 4. 抬起##     print("抬起物体...")##     mc.send_angles(TQ, SPEED)##     time.sleep(1)####     # 5. 移动到放置位置##     print("移动到放置位置...")##     mc.send_angles(FZ, SPEED)##     time.sleep(1)####     # 6. 打开夹爪（模拟放置）##     print("执行放置...")##     mc.set_gripper_value(255, 65)##     time.sleep(1.5)####     #7.回撤放回##     print("移动到安全区域...")##     mc.send_angles(HZ, SPEED)##     time.sleep(0.5)####     #8.回到最初##     print("移动到摄像位置")##     mc.send_angles(ZB, SPEED)##     time.sleep(0.5)